#!/usr/bin/perl
use strict;
use warnings;
use DBI;
use Carp;

# Database configuration - should be moved to environment variables or config file
# SECURITY WARNING: Hardcoded credentials should not be used in production.
# Use environment variables, a config file with restricted permissions, or a secrets manager.
my $db_name = $ENV{'LEGACY_DB_NAME'} || 'legacy_db';
my $db_host = $ENV{'LEGACY_DB_HOST'} || 'localhost';
my $db_user = $ENV{'LEGACY_DB_USER'} || die "ERROR: Database username must be set via LEGACY_DB_USER environment variable\n";
my $db_pass = $ENV{'LEGACY_DB_PASS'} || die "ERROR: Database password must be set via LEGACY_DB_PASS environment variable\n";
my $db_port = $ENV{'LEGACY_DB_PORT'} || 3306;

my $dsn = "DBI:mysql:database=$db_name;host=$db_host;port=$db_port";

# Connection options for robustness
my %db_options = (
    RaiseError           => 1,
    PrintError           => 0,
    AutoCommit           => 1,
    mysql_enable_utf8mb4 => 1,
    mysql_auto_reconnect => 1,
    mysql_connect_timeout => 10,
);

my $dbh;

sub db_connect {
    my $retry_count = 3;
    my $retry_delay = 2;

    for my $attempt (1 .. $retry_count) {
        eval {
            $dbh = DBI->connect($dsn, $db_user, $db_pass, \%db_options);
        };

        if ($@ || !$dbh) {
            my $error = $@ || DBI->errstr || 'Unknown error';
            warn "Database connection attempt $attempt of $retry_count failed: $error\n";

            if ($attempt < $retry_count) {
                warn "Retrying in $retry_delay seconds...\n";
                sleep($retry_delay);
                $retry_delay *= 2;    # Exponential backoff
            } else {
                croak "FATAL: Could not connect to database after $retry_count attempts: $error\n";
            }
        } else {
            print "Successfully connected to database '$db_name' on '$db_host:$db_port'\n";
            last;
        }
    }

    return $dbh;
}

sub db_disconnect {
    if ($dbh && $dbh->ping) {
        $dbh->disconnect();
        print "Database connection closed.\n";
    }
    return;
}

sub execute_query {
    my ($sql, @bind_params) = @_;

    my $sth;
    eval {
        $sth = $dbh->prepare($sql);
        $sth->execute(@bind_params);
    };

    if ($@) {
        croak "Query execution failed: $@\nSQL: $sql\n";
    }

    return $sth;
}

# --- Main execution ---

# Establish connection
$dbh = db_connect();

# Verify connectivity with a simple test query
